export const FICHES_BM = [
  {id:"bm_f1",title:"ISO 15189 et organisation du LBM",bloc:"Bloc 1",tags:["ISO 15189","Qualité","COFRAC","Organisation"],duree:18,niveau:"Fondations",qbank:"bm_fondamentaux",
    contenu:"**ISO 15189 — Norme LBM :**\n• Compétence technique + système de management de la qualité\n• Accréditation par le COFRAC (obligatoire en France depuis 2020)\n• Portée flexible : liste d'examens accrédités\n\n**Phases biologiques :**\n• Pré-analytique : prescription, prélèvement, transport, réception\n• Analytique : réalisation des analyses, CQI, CQA\n• Post-analytique : validation, rendu, archivage\n\n**Résultats critiques :** communication immédiate + traçabilité\n\n**Biologiste médical :** validation biologique, signature du compte rendu (responsabilité médicale)\n\n**POCT :** analyses délocalisées — cadre réglementaire strict (arrêté POCT, traçabilité, maintenance)"},
  {id:"bm_f2",title:"Hématologie avancée : myélogramme et SMP",bloc:"Bloc 2",tags:["Hématologie","Myélogramme","SMP","Hémopathies"],duree:20,niveau:"Avancé",qbank:"bm_hemato",
    contenu:"**Myélogramme :** ponction sternale → frottis MGG → formule médullaire\n\n**Syndromes myéloprolifératifs (SMP) :**\n• LMC : t(9;22) BCR-ABL (imatinib)\n• Polyglobulie de Vaquez : JAK2 V617F (95%)\n• Thrombocytémie essentielle : JAK2 (50%), MPL, CALR\n• Myélofibrose : moelle fibreuse (BOM indispensable)\n\n**Leucémies aiguës :**\n• LAM : blastes > 20% (blastose myéloïde), myéloperoxydase+\n• LAL : blastes lymphoïdes (TdT+, CD10+)\n• Classification OMS et cytogénétique\n\n**Myélome :** Ig monoclonale (pic M) + plasmocytose > 10% + complications (CRAB)\n\n**Anémies hémolytiques :**\n• Schizocytes → MAT (SHU, PTT, CIVD)\n• Coombs direct + → AHAI\n• Test de Kleihauer → hémorragie fœto-maternelle"},
  {id:"bm_f3",title:"Biologie moléculaire et génomique médicale",bloc:"Bloc 2",tags:["Biologie moléculaire","NGS","PCR","Génomique"],duree:22,niveau:"Avancé",qbank:"bm_fondamentaux",
    contenu:"**PCR et variantes :**\n• PCR conventionnelle : détection qualitative\n• qPCR (temps réel) : quantification (charge virale, expression génique)\n• PCR multiplex : plusieurs cibles simultanées (panel respiratoire, IST)\n• ddPCR (droplet digital) : quantification absolue ultra-sensible (MRD)\n\n**NGS (Séquençage Haut Débit) :**\n• Séquençage de millions de fragments simultanément\n• Panels ciblés (oncologie : BRCA, KRAS, EGFR)\n• Exome complet (WES) pour maladies rares\n• Génome complet (WGS)\n• Métagénomique (identification agents infectieux)\n\n**Applications cliniques :**\n• Oncologie : médecine de précision (thérapies ciblées)\n• Pharmacogénomique (CYP2D6, DPYD)\n• Maladies génétiques rares\n• Maladies infectieuses (résistances antibiotiques par NGS)"},
  ,{id:"bm_f5",title:"Fonction rénale et équilibre hydroélectrolytique",bloc:"Bloc 2",tags:["Rein","DFG","Sodium","Potassium","Osmolalité","ECBU"],duree:22,niveau:"Intermédiaire",qbank:"bm_rein_hydro",
    contenu:"**Structure du néphron :**\nGlomérule (capsule de Bowman) → TCP → anse de Henle → TCD → tube collecteur\n~1 million de néphrons par rein\n\n**Compartiments hydriques :**\n• ACT ≈ 60% du poids (42L pour 70kg)\n• LIC = 2/3 (28L) — K⁺ dominant (150 mmol/L)\n• LEC = 1/3 (14L) — Na⁺ dominant (135-145 mmol/L)\n• Osmolalité : 2×Na + glucose + urée (mmol/L) = 280-295 mOsm/kg\n\n**Régulation hormonale :**\n• ADH (neurohypophyse) : ↑ AQP2 → réabsorption eau → concentration urines\n• Aldostérone (SRAA) : ↑ ENaC → réabsorption Na⁺ + excrétion K⁺/H⁺\n\n**Marqueurs de la fonction rénale :**\n• Créatinine → formule CKD-EPI → DFG estimé\n• Cystatine C : meilleure si sarcopénie/obésité\n• DFG normal > 90 mL/min/1.73m²\n• IRC : G1 (>90) → G5 (<15 → dialyse)\n\n**Protéinurie :**\n• Normale < 150 mg/j\n• Micro-albuminurie : 30-300 mg/j\n• Macroprotéinurie > 300 mg/j (SNP > 3 g/j)\n\n**ECBU positif :** leucocyturie ≥ 10⁴/mL + bactériurie ≥ 10³-10⁵ UFC/mL"}
  ,{id:"bm_f4",title:"Biochimie spécialisée et techniques d'immunodosage",bloc:"Bloc 2",tags:["Biochimie","Marqueurs","ELISA","Immunodosage","LC-MS/MS"],duree:20,niveau:"Avancé",qbank:"bm_biochimie_spec",
    contenu:"**Marqueurs cardiaques :**\n• Troponine I/T (cTn) : nécrose myocardique (H2-4), high-sensitivity\n• NT-proBNP : insuffisance cardiaque (distension ventriculaire)\n• Myoglobine : précoce mais peu spécifique\n\n**Marqueurs tumoraux :**\n• AFP : CHC, tumeurs germinales\n• CA 125 : ovaire (suivi)\n• PSA : prostate (total + libre/total < 15% → suspect)\n• CEA : côlon (suivi rechute)\n• CA 19-9 : pancréas, voies biliaires\n\n**Techniques :**\n• ELISA (sandwich) : immunodosage de référence, 96 puits, révélation enzymatique\n• IFI (HEp-2) : AAN (aspect de fluorescence)\n• LC-MS/MS : gold standard stéroïdes, vitamines, immunosuppresseurs\n• Immunohistochimie : marqueurs tissulaires (récepteurs hormonaux, Ki67)\n\n**Marqueurs nutritionnels :**\n• Albumine (demi-vie 21j) : dénutrition chronique\n• Préalbumine (demi-vie 2-3j) : dénutrition aiguë / réponse nutritionnelle\n• CRP doit être < 10 pour interpréter correctement"}
  ,{id:"bm_f6",title:"Hémostase : coagulation, thrombophilie et anticoagulants",bloc:"Bloc 2",tags:["Hémostase","Coagulation","TP","TCA","INR","AVK","HBPM","AOD","CIVD"],duree:22,niveau:"Avancé",qbank:"bm_hemostase",
    contenu:"**Hémostase primaire :**\n• Vasoconstriction → adhésion plaquettaire (vWF-GPIb + collagène)\n• Activation (ADP, TXA2) → agrégation (fibrinogène + GPIIb/IIIa)\n• Résultat : clou plaquettaire (thrombus blanc)\n\n**Coagulation (hémostase secondaire) :**\n• Voie extrinsèque : facteur VII + TF (facteur tissulaire) → explorée par le TP\n• Voie intrinsèque : XII, XI, IX, VIII → explorée par le TCA\n• Voie commune : X, V, II (prothrombine), I (fibrinogène) → fibrine insoluble\n• Fibrinogène normal : 2-4 g/L\n\n**Tests biologiques :**\n• TP (Taux de prothrombine) : normal > 70% → ↓ si AVK, insuffisance hépatique, CIVD\n• INR = standardisation du TP → cible 2-3 (FA, MTEV) ou 2.5-3.5 (valve mécanique)\n• TCA : normal < 1.2 × témoin → allongé si hémophilie A (FVIII↓), hémophilie B (FIX↓), SAPL\n• D-dimères < 500 µg/L : VPN excellente pour exclure TVP/EP\n• Fibrinogène effondré + D-dimères >> = CIVD\n\n**Anticoagulants :**\n• AVK (warfarine, fluindione) : inhibent facteurs II, VII, IX, X, protéines C et S → surveillance INR\n• HNF : inhibe IIa et Xa → surveillance TCA ou anti-Xa\n• HBPM (enoxaparine) : anti-Xa >> anti-IIa → surveillance anti-Xa si obésité/grossesse/IRC\n• AOD anti-Xa : rivaroxaban, apixaban, edoxaban (pas de surveillance systématique)\n• AOD anti-IIa : dabigatran\n• TIH2 : anticorps anti-PF4/héparine → thromboses paradoxales, arrêter héparine\n\n**Thrombophilies héréditaires :**\n• Facteur V Leiden (R506Q) : résistance PCa → thrombophilie la + fréquente en Europe\n• Mutation prothrombine G20210A\n• Déficits AT III, protéine C, protéine S"}
  ,{id:"bm_f7",title:"Immunopathologie et auto-anticorps",bloc:"Bloc 2",tags:["Auto-immunité","AAN","Anti-ADN","FR","Anti-CCP","ANCA","Complément","Lupus"],duree:20,niveau:"Avancé",qbank:"bm_immunopath",
    contenu:"**Dépistage des AAN :**\n• IFI sur cellules HEp-2 (immunofluorescence indirecte)\n• Patterns : homogène (anti-ADNdb → LES), moucheté (anti-ENA), nucléolaire (anti-PM/Scl), centromérique (CREST/sclérodermie)\n• Seuil significatif : ≥ 1/160\n\n**Maladies auto-immunes spécifiques :**\n• LES : anti-ADNn (spécificité > 97%), anti-Sm, hypocomplémentémie C3+C4\n• PR : FR (IgM anti-IgG, Se 70%, Sp 80%) + anti-CCP (Se 67%, Sp > 95%)\n• Sjögren primaire : anti-SSA/Ro, anti-SSB/La\n• Sclérodermie : anti-Scl70 (diffuse), anti-centromères (limitée/CREST)\n• SAPL : anti-cardiolipine + anti-β2GPI + anticoagulant lupique (TCA allongé + thromboses)\n\n**Thyroïde auto-immune :**\n• Hashimoto (hypothyroïdie) : anti-TPO ++ (95%), TSH ↑, T4L ↓\n• Basedow (hyperthyroïdie) : anti-RTSH stimulants (TRAK) → stimulation permanente\n\n**Vascularites :**\n• c-ANCA / anti-PR3 : granulomatose avec polyangéite (Wegener)\n• p-ANCA / anti-MPO : polyangéite microscopique\n\n**Complément :**\n• C3 + C4 bas → activation voie classique (LES, cryoglobulinémie)\n• C3 bas + C4 normal → activation voie alterne (GN membranoproliférative)\n\n**Immunohématologie :**\n• TCD (Coombs direct) : Ac fixés sur GR du patient → AHAI, MHN, réaction transfusionnelle"}
  ,{id:"bm_f8",title:"Microbiologie clinique avancée : résistances et diagnostic",bloc:"Bloc 2",tags:["Microbiologie","SARM","BLSE","EPC","ECBU","Hémocultures","Antibiogramme","EUCAST"],duree:22,niveau:"Avancé",qbank:"bm_micro_bm",
    contenu:"**Prélèvements bactériologiques :**\n• Hémocultures : avant ATB, 2-3 paires aéro-anaérobies → détection CO₂ (BACTEC/BacT-Alert)\n• ECBU : leucocyturie ≥ 10⁴/mL + bactériurie ≥ 10⁵ UFC/mL (mi-jet, < 2h)\n• LCR urgent : cytologie + biochimie (glucose/protéines) + Gram + culture\n\n**Résistances bactériennes :**\n• SARM : gène mecA/mecC → PLP2a → résistance toutes bêtalactamines\n• BLSE : enzyme plasmidique hydrolysant C3G → test synergie (double disque)\n• EPC / KPC : carbapénémase hydrolysant les carbapénèmes → urgence infectieuse\n• Détection : phénotypique + confirmation moléculaire (PCR mecA, KPC…)\n\n**Antibiogramme et EUCAST :**\n• Méthode diffusion disque sur Mueller-Hinton → diamètre → catégories S/I/R\n• EUCAST : référentiel européen (CA-SFM), mis à jour annuellement\n• 'I' = sensible pour posologie forte (remplace 'intermédiaire')\n\n**Diagnostic moléculaire :**\n• PCR 16S ARNr : identification universelle bactéries non cultivables\n• Xpert MTB/RIF : détecte M. tuberculosis + résistance rifampicine en 2h\n• Sérologie VIH 4e génération : Ag p24 + Ac anti-VIH (fenêtre sérologique ~18j)\n\n**Mycobactériologie :**\n• Tuberculose : examen direct (Ziehl-Neelsen), culture Löwenstein-Jensen (3-6 sem) ou MGIT (2-3 sem), Xpert MTB/RIF\n• MDR-TB = résistance INH + rifampicine"}
  ,{id:"bm_f9",title:"Génétique médicale : diagnostic et oncogénétique",bloc:"Bloc 2",tags:["Génétique","Caryotype","FISH","NGS","BRCA","Lynch","Pharmacogénomique","ddPCR"],duree:22,niveau:"Avancé",qbank:"bm_genetique",
    contenu:"**Analyses chromosomiques :**\n• Caryotype : lymphocytes → culture 72h (PHA) → colcémide → coloration GTG → bandes\n• FISH : sondes fluorescentes sur noyaux en interphase ou métaphase → anomalies ciblées\n  (BCR-ABL/LMC, HER2 amplification, t(14;18)/lymphome folliculaire)\n\n**Maladies génétiques courantes :**\n• Trisomie 21 : 95% non-disjonction méiotique (47,+21) → DPNI en dépistage\n• Mucoviscidose : CFTR (F508del 70%), AR → test sueur Cl⁻ > 60 mmol/L\n• DPNI : ADN fœtal libre (cffDNA) dans sang maternel → Se > 99% T21/T18/T13\n\n**Oncogénétique :**\n• BRCA1/2 : syndrome HBOC → cancer sein (60-80%), ovaire (40-60%) → inhibiteurs PARP\n• Lynch/HNPCC : mutations MMR (MLH1, MSH2, MSH6, PMS2) → instabilité microsatellitaire (MSI)\n• MSI-H sur tumeur : prédictif réponse aux anti-PD1 (pembrolizumab)\n\n**Séquençage de nouvelle génération (NGS) :**\n• Panels oncologiques : mutations somatiques actionnables (EGFR, BRAF, KRAS, ALK, HER2)\n• Médecine de précision : thérapies ciblées guidées par le profil moléculaire tumoral\n• ddPCR : quantification ultra-sensible (ctDNA, MRD) → détecte 0.01% d'allèles mutés\n\n**Pharmacogénomique :**\n• CYP2D6 : métaboliseurs lents (accumulation) vs ultra-rapides (sous-dosage)\n  → codéine chez MU → morphine excessive → dépression respiratoire\n• DPYD, TPMT, UGT1A1 : toxicités chimiothérapies (5-FU, mercaptopurine, irinotécan)\n\n**Réglementation :**\n• Test génétique constitutionnel : consentement écrit + conseil génétique (médecin habilité)"}
  ,...FICHES_PC
];

